class Solution(object):
    def buttonWithLongestTime(self, events):
        best_idx = events[0][0]
        best_time = events[0][1]
        for i in range(1, len(events)):
            t = events[i][1] - events[i - 1][1]
            idx = events[i][0]
            if t > best_time or (t == best_time and idx < best_idx):
                best_time = t
                best_idx = idx
        return best_idx
